import React, { useState, useEffect } from 'react';
import AdminNavbar from '../components/AdminNavbar';
import AdminSidebar from '../components/AdminSidebar';
import { useBookings } from '../context/BookingContext';
import { useVehicles } from '../context/VehicleContext';

const AdminDashboard = () => {
  const { getBookings, getPayments } = useBookings();
  const { vehicles } = useVehicles();
  const [stats, setStats] = useState({
    activeRentals: 0,
    vehiclesAvailable: 0,
    upcomingReservations: 0,
    totalEarnings: 0,
    totalBookings: 0,
    totalCustomers: 0
  });
  const [recentBookings, setRecentBookings] = useState([]);

  useEffect(() => {
    const allBookings = getBookings();
    const allPayments = getPayments();
    
    // Calculate statistics
    const activeRentals = allBookings.filter(b => b.status === 'Approved').length;
    const vehiclesAvailable = vehicles.filter(v => v.status === 'active').length;
    const upcomingReservations = allBookings.filter(b => b.status === 'Pending').length;
    const completedPayments = allPayments.filter(p => p.status === 'Completed');
    const totalEarnings = completedPayments.reduce((sum, p) => sum + (p.amount || 0), 0);
    
    // Get unique customers
    const uniqueCustomers = new Set(allBookings.map(b => b.userId)).size;
    
    setStats({
      activeRentals,
      vehiclesAvailable,
      upcomingReservations,
      totalEarnings,
      totalBookings: allBookings.length,
      totalCustomers: uniqueCustomers
    });
    
    // Get recent bookings (last 5)
    const sorted = [...allBookings].sort((a, b) => {
      const dateA = new Date(a.createdAt || 0);
      const dateB = new Date(b.createdAt || 0);
      return dateB - dateA;
    }).slice(0, 5);
    setRecentBookings(sorted);
  }, [getBookings, getPayments, vehicles]);

  return (
    <div style={styles.container}>
      <AdminNavbar />
      <AdminSidebar />
      
      <main style={styles.mainContent}>
        <div style={styles.contentWrapper}>
          <h2 style={styles.pageTitle}>Dashboard Summary</h2>

          {/* Cards Row */}
          <div style={styles.cardsRow}>
            <div style={styles.card} aria-label={`Active Rentals ${stats.activeRentals}`}>
              <div style={styles.cardTitle}>Active Rentals</div>
              <div style={styles.cardValue}>{stats.activeRentals}</div>
              <div style={styles.cardIcon}>
                <svg viewBox="0 0 24 24" fill="#2b46ef" width="32" height="24">
                  <path d="M4 6h16v9h2v1h-1v4a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1v-4H2v-1h2V6Zm1 2v7h4v-7H5Zm12 7v-7h-4v7h4Zm-9-5h1v3h-1v-3Zm6 0h1v3h-1v-3Z"/>
                </svg>
              </div>
            </div>
            
            <div style={styles.card} aria-label={`Vehicles Available ${stats.vehiclesAvailable}`}>
              <div style={styles.cardTitle}>Vehicles Available</div>
              <div style={styles.cardValue}>{stats.vehiclesAvailable}</div>
              <div style={styles.cardIcon}>
                <svg viewBox="0 0 24 24" fill="#ff7a1e" width="32" height="24">
                  <path d="M3 11v6a3 3 0 0 0 6 0v-6H3Zm14 0v6a3 3 0 0 0 6 0v-6h-6ZM3 18v2h18v-2H3Z"/>
                </svg>
              </div>
            </div>
            
            <div style={styles.card} aria-label={`Upcoming Reservations ${stats.upcomingReservations}`}>
              <div style={styles.cardTitle}>Upcoming Reservations</div>
              <div style={styles.cardValue}>{stats.upcomingReservations}</div>
              <div style={styles.cardIcon}>
                <svg viewBox="0 0 24 24" fill="#2bc534" width="32" height="24">
                  <path d="M7 11h10M7 15h7m-2-7V3H9v4H7a1 1 0 0 0-1 1v13h12V7a1 1 0 0 0-1-1h-2V3h-2v4Z"/>
                </svg>
              </div>
            </div>
            
            <div style={{...styles.card, ...styles.cardEarnings}} aria-label={`Total Earnings ${stats.totalEarnings} Philippine Peso`}>
              <div style={{...styles.cardTitle, marginBottom: '5px'}}>Php</div>
              <div style={styles.cardEarningsValue}>{stats.totalEarnings.toLocaleString()}.00</div>
            </div>
          </div>

          {/* Stats and Recent Bookings */}
          <div style={styles.statsSection}>
            <section style={styles.statsContainer} aria-label="Rental Statistics Section">
              <div style={styles.statsHeader}>
                <h3 style={styles.statsTitle}>Rental Statistics</h3>
                <div style={styles.btnGroup} role="tablist" aria-label="Toggle rental statistics view">
                  <button style={{...styles.btn, ...styles.btnWeekly, ...styles.btnActive}} role="tab" aria-selected="true" tabIndex="0">Weekly</button>
                  <button style={{...styles.btn, ...styles.btnMonthly}} role="tab" aria-selected="false" tabIndex="-1">Monthly</button>
                </div>
              </div>
              <div style={styles.chartWrapper}>
                <canvas id="rentalChart" aria-hidden="true"></canvas>
              </div>
            </section>

            <aside style={styles.recentBookings} aria-label="Recent Bookings Summary">
              <h3 style={styles.recentTitle}>Recent Bookings</h3>
              {recentBookings.length === 0 ? (
                <div style={styles.noBookings}>No recent bookings</div>
              ) : (
                recentBookings.map(booking => (
                  <div key={booking.id} style={styles.bookingDetails} aria-live="polite">
                    Booking <span style={styles.bookingId}>{booking.id?.slice(-6).toUpperCase() || 'N/A'}</span>
                    <span style={styles.bookingValue}>₱{booking.totalPrice?.toLocaleString() || 0}</span>
                    <div style={styles.subItem}><span>{booking.userName || 'Unknown User'}</span></div>
                    <div style={styles.subItem}>Vehicle: {booking.carName || 'N/A'}</div>
                    <div style={styles.subItem}>Date: {booking.startDate} - {booking.endDate}</div>
                    <div style={styles.subItem}>
                      Status: <span style={{
                        ...styles.statusBadge,
                        backgroundColor: booking.status === 'Approved' ? '#28a745' : 
                          booking.status === 'Pending' ? '#ffc107' : 
                          booking.status === 'Completed' ? '#3a913f' : '#dc3545'
                      }}>{booking.status || 'Pending'}</span>
                    </div>
                  </div>
                ))
              )}
            </aside>
          </div>

          {/* Quick Stats Row */}
          <div style={styles.quickStats}>
            <div style={styles.quickStat}>
              <span style={styles.quickStatValue}>{stats.totalBookings}</span>
              <span style={styles.quickStatLabel}>Total Bookings</span>
            </div>
            <div style={styles.quickStat}>
              <span style={styles.quickStatValue}>{stats.totalCustomers}</span>
              <span style={styles.quickStatLabel}>Total Customers</span>
            </div>
            <div style={styles.quickStat}>
              <span style={styles.quickStatValue}>{vehicles.length}</span>
              <span style={styles.quickStatLabel}>Total Vehicles</span>
            </div>
          </div>

          {/* Info Row */}
          <section style={styles.infoRow} aria-label="Car rental benefits">
            <div style={styles.infoBox}>
              <svg viewBox="0 0 64 64" fill="none" stroke="currentColor" strokeWidth="1.8" style={styles.infoSvg}>
                <path d="M9 52h46M12 44h40M16 36h32M20 28h24M24 20h16" />
              </svg>
              <div style={styles.infoText}>
                <strong>Affordable Rates</strong>
                <span>Great prices on all vehicle types</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 50 50" fill="none" stroke="currentColor" strokeWidth="2" style={styles.infoSvg}>
                <circle cx="25" cy="25" r="24" />
                <path d="M21 18v9l6 3" />
                <path d="M25 31v-8" />
              </svg>
              <div style={styles.infoText}>
                <strong>Safety &amp; Security</strong>
                <span>Well-maintained and safe rental cars</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 22 22" fill="none" stroke="currentColor" strokeWidth="2" style={styles.infoSvg}>
                <path d="M2 16v1a5 5 0 0 0 10 0v-1" />
                <path d="M17 12v-6a5 5 0 0 0-10 0v6" />
              </svg>
              <div style={styles.infoText}>
                <strong>Easy Booking</strong>
                <span>Quick and Hassle free online reservations</span>
              </div>
            </div>
          </section>
        </div>
      </main>

      <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
      <script dangerouslySetInnerHTML={{
        __html: `
          const ctx = document.getElementById('rentalChart');
          if (ctx) {
            const chartCtx = ctx.getContext('2d');
            const weeklyData = {
              labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
              datasets: [
                {
                  label: '% Rental 1',
                  type: 'line',
                  data: [7, 14, 12, 16, 29, 20, 32],
                  borderColor: '#2846e3',
                  backgroundColor: '#2846e3',
                  fill: false,
                  tension: 0.35,
                  pointRadius: 5,
                  yAxisID: 'y',
                },
                {
                  label: '% Rental 2',
                  type: 'line',
                  data: [2, 10, 6, 16, 12, 20, 16],
                  borderColor: '#d18029',
                  backgroundColor: '#d18029',
                  fill: false,
                  tension: 0.35,
                  pointRadius: 5,
                  yAxisID: 'y',
                },
                {
                  label: 'Rental Volume',
                  type: 'bar',
                  data: [1, 4, 8, 9, 15, 12, 20],
                  backgroundColor: '#acc8ff',
                  borderRadius: 5,
                  yAxisID: 'y1',
                }
              ]
            };

            const config = {
              type: 'bar',
              data: weeklyData,
              options: {
                responsive: true,
                maintainAspectRatio: false,
                interaction: { mode: 'nearest', intersect: false },
                scales: {
                  y: {
                    type: 'linear',
                    position: 'left',
                    min: 0,
                    max: 40,
                    ticks: { stepSize: 5, color: '#2846e3', font: { weight: 'bold' } },
                    grid: { color: '#c7d2f9' }
                  },
                  y1: {
                    type: 'linear',
                    position: 'right',
                    min: 0,
                    max: 30,
                    grid: { drawOnChartArea: false },
                    ticks: { stepSize: 5, color: '#acc8ff', font: { weight: 'bold' } }
                  }
                },
                plugins: {
                  legend: { labels: { font: { weight: 'bold', size: 14 } } },
                  tooltip: { mode: 'index', intersect: false, backgroundColor: '#2a46e7', titleFont: { weight: 'bold' }, bodyFont: { weight: '600' } }
                }
              }
            };

            new Chart(chartCtx, config);
          }
        `
      }} />

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inria+Serif&display=swap');
        * { box-sizing: border-box; }
      `}</style>
    </div>
  );
};

const styles = {
  container: { display: 'flex', minHeight: '100vh', backgroundColor: '#e7f0fd', fontFamily: 'Inria Serif, serif' },
  mainContent: { flex: 1, marginLeft: '250px', marginTop: '60px', padding: '20px' },
  contentWrapper: { maxWidth: '1040px', margin: '0 auto' },
  pageTitle: { marginBottom: '22px', fontWeight: '700', fontSize: '22px' },
  cardsRow: { display: 'flex', gap: '20px', flexWrap: 'wrap', marginBottom: '26px' },
  card: { flex: '1 1 170px', background: '#fff', borderRadius: '10px', boxShadow: '0 3px 6px rgb(102 113 138 / 0.4)', padding: '16px 20px 20px', color: '#373737', fontWeight: '600', fontSize: '18px', position: 'relative', minWidth: '170px' },
  cardTitle: { fontWeight: '600', fontSize: '14px', color: '#6b799f' },
  cardValue: { marginTop: '8px', fontWeight: '700', fontSize: '26px' },
  cardIcon: { position: 'absolute', top: '12px', right: '14px', width: '32px', height: '24px' },
  cardEarnings: { color: '#22821d' },
  cardEarningsValue: { marginTop: '8px', fontWeight: '700', fontSize: '28px', letterSpacing: '0.8px' },
  statsSection: { display: 'flex', gap: '25px', flexWrap: 'wrap' },
  statsContainer: { background: '#fff', borderRadius: '12px', boxShadow: '2px 6px 20px rgb(102 105 138 / 0.25)', padding: '18px 20px 15px', flex: '1 1 670px', minWidth: '300px' },
  statsHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' },
  statsTitle: { fontWeight: '700', fontSize: '21px', color: '#222233' },
  btnGroup: { display: 'flex', gap: '12px' },
  btn: { borderRadius: '6px', border: 'none', padding: '6px 16px', fontWeight: '700', fontSize: '13px', cursor: 'pointer', color: 'white', transition: 'filter 0.25s ease' },
  btnWeekly: { backgroundColor: '#2846e3' },
  btnMonthly: { backgroundColor: '#2bb934' },
  btnActive: { boxShadow: '0 1px 10px rgba(40,70,227,0.8)', cursor: 'default' },
  chartWrapper: { background: '#f3f6fb', padding: '12px 14px 6px 16px', borderRadius: '8px', boxShadow: 'inset -3px 0 18px #e6ecfb, inset 0 3px 10px #e6ecfb' },
  recentBookings: { maxWidth: '320px', background: 'white', borderRadius: '10px', boxShadow: '3px 7px 22px rgb(9 11 83 / 0.15)', padding: '20px 24px 26px 26px', flex: '1 1 300px' },
  recentTitle: { fontWeight: '700', fontSize: '20px', color: '#222', marginBottom: '14px' },
  noBookings: { textAlign: 'center', padding: '20px', color: '#666' },
  bookingDetails: { fontSize: '13px', color: '#3f5369', lineHeight: '1.3', marginBottom: '15px', paddingBottom: '15px', borderBottom: '1px solid #eee' },
  bookingId: { color: '#2a46ff', textDecoration: 'underline', cursor: 'pointer', fontWeight: '600' },
  bookingValue: { fontWeight: '700', color: '#222', marginLeft: '6px' },
  subItem: { marginLeft: '16px', marginTop: '5px', fontWeight: '600', color: '#646464' },
  statusBadge: { padding: '2px 8px', borderRadius: '4px', fontSize: '11px', color: 'white' },
  quickStats: { display: 'flex', gap: '15px', marginTop: '20px', flexWrap: 'wrap' },
  quickStat: { flex: '1 1 0', background: 'white', padding: '15px 20px', borderRadius: '8px', textAlign: 'center', minWidth: '120px' },
  quickStatValue: { display: 'block', fontSize: '24px', fontWeight: '700', color: '#2846e3' },
  quickStatLabel: { fontSize: '12px', color: '#666', fontWeight: '600' },
  infoRow: { marginTop: '33px', background: 'white', borderRadius: '10px', boxShadow: '0 2px 6px rgba(0,0,0,0.12)', padding: '22px 30px', display: 'flex', gap: '38px', justifyContent: 'space-between' },
  infoBox: { display: 'flex', gap: '20px', maxWidth: '390px' },
  infoSvg: { width: '46px', height: '46px', stroke: '#222' },
  infoText: { display: 'flex', flexDirection: 'column', justifyContent: 'center' },
};

export default AdminDashboard;
